import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { 
  Users, 
  Phone, 
  Megaphone, 
  Shield, 
  Search, 
  Building, 
  Award,
  TrendingUp,
  Clock,
  AlertTriangle,
  CheckCircle,
  Plus,
  Activity
} from 'lucide-react';
import { useTask } from '../contexts/TaskContext';
import { complaintAPI } from '../services/api';

const Dashboard = () => {
  const { stats, clearError } = useTask();
  const [allTasks, setAllTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Role configurations
  const roles = [
    {
      name: 'Customer Service',
      path: '/customer',
      icon: Users,
      color: 'blue',
      description: 'Handle customer inquiries',
      group: 'customer'
    },
    {
      name: 'Branch Staff',
      path: '/branch-staff',
      icon: Building,
      color: 'green',
      description: 'Branch operations',
      group: 'branch-staff'
    },
    {
      name: 'Contact Center',
      path: '/contact-center',
      icon: Phone,
      color: 'purple',
      description: 'Customer support',
      group: 'contact-center'
    },
    {
      name: 'Marketing',
      path: '/marketing',
      icon: Megaphone,
      color: 'orange',
      description: 'Marketing complaints',
      group: 'marketing'
    },
    {
      name: 'CMD',
      path: '/cmd',
      icon: Shield,
      color: 'red',
      description: 'Management decisions',
      group: 'cmd'
    },
    {
      name: 'Audit',
      path: '/audit',
      icon: Search,
      color: 'indigo',
      description: 'Investigations',
      group: 'audit'
    },
    {
      name: 'Work Unit',
      path: '/work-unit',
      icon: Building,
      color: 'yellow',
      description: 'Department tasks',
      group: 'work-unit'
    },
    {
      name: 'Service Quality',
      path: '/service-quality',
      icon: Award,
      color: 'pink',
      description: 'Quality assurance',
      group: 'service-quality'
    }
  ];

  // Fetch tasks for all roles to get overview statistics
  useEffect(() => {
    const fetchAllTasks = async () => {
      try {
        setLoading(true);
        setError(null);
        clearError();

        const response = await complaintAPI.getEnrichedTasks();
        setAllTasks(response.data);
      } catch (err) {
        setError(err.response?.data?.error || err.message || 'Failed to fetch dashboard data');
      } finally {
        setLoading(false);
      }
    };

    fetchAllTasks();
  }, [clearError]);

  // Calculate role-specific stats
  const getRoleStats = (group) => {
    const roleTasks = allTasks.filter(task => 
      task.candidateGroup === group || 
      task.assignee?.includes(group) ||
      task.name?.toLowerCase().includes(group.replace('-', ' '))
    );

    return {
      total: roleTasks.length,
      onTime: roleTasks.filter(t => t.slaStatus === 'ON_TIME').length,
      approaching: roleTasks.filter(t => t.slaStatus === 'APPROACHING').length,
      breached: roleTasks.filter(t => t.slaStatus === 'BREACHED').length,
      highPriority: roleTasks.filter(t => t.priority === 'P1').length,
    };
  };

  const getRoleColorClasses = (color) => {
    const colors = {
      blue: 'bg-blue-50 text-blue-600 border-blue-200 hover:bg-blue-100',
      green: 'bg-green-50 text-green-600 border-green-200 hover:bg-green-100',
      purple: 'bg-purple-50 text-purple-600 border-purple-200 hover:bg-purple-100',
      orange: 'bg-orange-50 text-orange-600 border-orange-200 hover:bg-orange-100',
      red: 'bg-red-50 text-red-600 border-red-200 hover:bg-red-100',
      indigo: 'bg-indigo-50 text-indigo-600 border-indigo-200 hover:bg-indigo-100',
      yellow: 'bg-yellow-50 text-yellow-600 border-yellow-200 hover:bg-yellow-100',
      pink: 'bg-pink-50 text-pink-600 border-pink-200 hover:bg-pink-100',
    };
    return colors[color] || 'bg-gray-50 text-gray-600 border-gray-200 hover:bg-gray-100';
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-4">
        <div className="flex items-center">
          <AlertTriangle className="w-5 h-5 text-red-600 mr-2" />
          <p className="text-red-800">{error}</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Dashboard Overview</h1>
          <p className="text-gray-600">Complaint Management System at a glance</p>
        </div>
        <Link
          to="/complaint-registration"
          className="flex items-center space-x-2 bg-primary-600 text-white px-4 py-2 rounded-lg hover:bg-primary-700 transition-colors"
        >
          <Plus className="w-5 h-5" />
          <span>New Complaint</span>
        </Link>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Total Tasks</p>
              <p className="text-2xl font-bold text-gray-900">{stats.total}</p>
            </div>
            <div className="bg-blue-100 rounded-full p-3">
              <Activity className="w-6 h-6 text-blue-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">On Time</p>
              <p className="text-2xl font-bold text-success-600">{stats.onTime}</p>
            </div>
            <div className="bg-green-100 rounded-full p-3">
              <CheckCircle className="w-6 h-6 text-green-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Approaching</p>
              <p className="text-2xl font-bold text-warning-600">{stats.approaching}</p>
            </div>
            <div className="bg-yellow-100 rounded-full p-3">
              <Clock className="w-6 h-6 text-yellow-600" />
            </div>
          </div>
        </div>

        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">Breached</p>
              <p className="text-2xl font-bold text-danger-600">{stats.breached}</p>
            </div>
            <div className="bg-red-100 rounded-full p-3">
              <AlertTriangle className="w-6 h-6 text-red-600" />
            </div>
          </div>
        </div>
      </div>

      {/* Role-based Dashboard Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {roles.map((role) => {
          const Icon = role.icon;
          const roleStats = getRoleStats(role.group);
          const colorClasses = getRoleColorClasses(role.color);

          return (
            <Link
              key={role.group}
              to={role.path}
              className={`bg-white rounded-lg shadow-md border-2 transition-all duration-200 hover:shadow-lg ${colorClasses}`}
            >
              <div className="p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className={`rounded-lg p-3 ${colorClasses.split(' ')[0]}`}>
                    <Icon className="w-6 h-6" />
                  </div>
                  {roleStats.total > 0 && (
                    <span className="bg-gray-100 text-gray-800 text-xs px-2 py-1 rounded-full">
                      {roleStats.total}
                    </span>
                  )}
                </div>

                <h3 className="font-semibold text-lg mb-1">{role.name}</h3>
                <p className="text-sm opacity-75 mb-4">{role.description}</p>

                {roleStats.total > 0 && (
                  <div className="space-y-2 text-sm">
                    <div className="flex justify-between">
                      <span>On Time:</span>
                      <span className="font-medium">{roleStats.onTime}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Approaching:</span>
                      <span className="font-medium">{roleStats.approaching}</span>
                    </div>
                    <div className="flex justify-between">
                      <span>Breached:</span>
                      <span className="font-medium">{roleStats.breached}</span>
                    </div>
                    {roleStats.highPriority > 0 && (
                      <div className="flex justify-between font-medium text-red-600">
                        <span>High Priority:</span>
                        <span>{roleStats.highPriority}</span>
                      </div>
                    )}
                  </div>
                )}

                <div className="mt-4 flex items-center text-sm font-medium">
                  <span>View Dashboard</span>
                  <TrendingUp className="w-4 h-4 ml-1" />
                </div>
              </div>
            </Link>
          );
        })}
      </div>

      {/* Recent Activity */}
      <div className="bg-white rounded-lg shadow">
        <div className="px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900">Recent Activity</h2>
        </div>
        <div className="p-6">
          {allTasks.length > 0 ? (
            <div className="space-y-4">
              {allTasks.slice(0, 5).map((task) => (
                <div key={task.id} className="flex items-center justify-between py-3 border-b border-gray-100 last:border-0">
                  <div className="flex-1">
                    <p className="text-sm font-medium text-gray-900">{task.name}</p>
                    <p className="text-xs text-gray-500">
                      {task.customerName} • {task.complaintId}
                    </p>
                  </div>
                  <div className="flex items-center space-x-3">
                    <span className={`text-xs px-2 py-1 rounded-full ${
                      task.slaStatus === 'ON_TIME' ? 'bg-green-100 text-green-800' :
                      task.slaStatus === 'APPROACHING' ? 'bg-yellow-100 text-yellow-800' :
                      'bg-red-100 text-red-800'
                    }`}>
                      {task.slaStatus}
                    </span>
                    <span className="text-xs text-gray-500">{task.createdAt}</span>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-gray-500 text-center py-8">No recent activity</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
